265→function buildSeedEntityContent(kind: string, text: string, now: Date): Record<string, unknown> {
266→  const base = { created_at: now, updated_at: now };
267→  if (kind === "project") return { ...base, name: text, status: "active" };
268→  if (kind === "feature") return { ...base, name: text, status: "active" };
269→  if (kind === "task") return { ...base, title: text, status: "open" };
270→  if (kind === "decision") return { ...base, summary: text, status: "extracted" };
271→  return { ...base, text, status: "open" };
272→}
273→
274→export function createEventCollector(): SseRegistry & { getEvents(messageId: string): StreamEvent[] } {
275→  const events = new Map<string, StreamEvent[]>();
276→  return {
277→    registerMessage(messageId: string) {
278→      events.set(messageId, []);
279→    },
280→    handleStreamRequest(_messageId: string): Response {
281→      throw new Error("handleStreamRequest not available in eval mode");
282→    },
283→    emitEvent(messageId: string, event: StreamEvent) {
284→      events.get(messageId)?.push(event);
285→    },
286→    getEvents(messageId: string): StreamEvent[] {
287→      return events.get(messageId) ?? [];
288→    },
289→  };
290→}
291→
292→function isAlreadyExistsError(error: unknown): boolean {
293→  return error instanceof Error && error.message.includes("already exists");
294→}
295→
296→function requireEnv(name: string): string {
297→  const value = process.env[name];
298→  if (!value || value.trim().length === 0) {
299→    throw new Error(`Missing required environment variable: ${name}`);
300→  }
301→  return value;
302→}
